    static final Map<String, Integer> MAX_WORD_COUNTS;

    static {
        Map<String, Integer> maxWords = new HashMap<>(5);
        maxWords.put("AU", 2);
        maxWords.put("DEFAULT", 3);
        maxWords.put("FDA", 1);
        maxWords.put("ISMP", 2);
        maxWords.put("NZ", 3);
        MAX_WORD_COUNTS = Collections.unmodifiableMap(maxWords);
    }

    static final Map<String, String> VERSIONS;

    static {
        Map<String, String> versions = new HashMap<>(5);
        versions.put("AU", "20240400.0");
        versions.put("DEFAULT", "20260612.0");
        versions.put("FDA", "20260612.0");
        versions.put("ISMP", "20260612.0");
        versions.put("NZ", "20231000.0");
        VERSIONS = Collections.unmodifiableMap(versions);
    }

    static final Set<String> AVAILABLE_LIST_IDS;

    static {
        Set<String> ids = new HashSet<>(5);
        ids.add("AU");
        ids.add("DEFAULT");
        ids.add("FDA");
        ids.add("ISMP");
        ids.add("NZ");
        AVAILABLE_LIST_IDS = Collections.unmodifiableSet(ids);
    }

    /** Return the casefold-to-canonical map for listId. */
    static Map<String, String> getList(String listId) {
        Map<String, String> list = ALL_LISTS.get(listId);
        if (list != null) {
            return list;
        }
        String available = String.join(", ", AVAILABLE_LIST_IDS.stream().sorted().toArray(String[]::new));
        throw new TallmanException("Unknown Tallman list ID: '" + listId + "'. Available lists: " + available + ".");
    }

    /** Return the maxWords lookahead cap for listId (default 1). */
    static int getMaxWordCount(String listId) {
        return MAX_WORD_COUNTS.getOrDefault(listId, 1);
    }

    /** Return the version string for listId. */
    static String getVersion(String listId) {
        String version = VERSIONS.get(listId);
        if (version != null) {
            return version;
        }
        String available = String.join(", ", AVAILABLE_LIST_IDS.stream().sorted().toArray(String[]::new));
        throw new TallmanException("Unknown Tallman list ID: '" + listId + "'. Available lists: " + available + ".");
    }

    /** Return true if listId is a known list. */
    static boolean hasList(String listId) {
        return ALL_LISTS.containsKey(listId);
    }

    /** Return an unmodifiable view of all available list IDs. */
    static Set<String> availableListIds() {
        return AVAILABLE_LIST_IDS;
    }

